  // A = alphabet array, F = frequency array, n = size
  // Step 1: Build the Huffman tree
  tree = BUILD-HUFFMAN-TREE(A, F, n)

  // Step 2: Assign binary codes by tree path
  codes = ASSIGN-CODES(tree.root, "")

  // Step 3: Encode or decode messages using the codes
  return codes

ASSIGN-CODES(node, prefix):
  if node is a leaf:
    node.code = prefix
    return
  ASSIGN-CODES(node.left,  prefix + "0")
  ASSIGN-CODES(node.right, prefix + "1")
