#include <string>
#include <unordered_map>
#include <queue>
using namespace std;

struct HuffNode {
    char ch;
    int freq;
    HuffNode* left;
    HuffNode* right;
    HuffNode(char c, int f) : ch(c), freq(f), left(nullptr), right(nullptr) {}
    HuffNode(int f, HuffNode* l, HuffNode* r) : ch('\0'), freq(f), left(l), right(r) {}
};

struct Compare {
    bool operator()(HuffNode* a, HuffNode* b) { return a->freq > b->freq; }
};

// Recursively assign codes by traversing tree paths
void assignCodes(HuffNode* node, const string& prefix,
                 unordered_map<char, string>& codes) {
    if (!node) return;
    if (!node->left && !node->right) {
        codes[node->ch] = prefix.empty() ? "0" : prefix;
        return;
    }
    assignCodes(node->left,  prefix + "0", codes);
    assignCodes(node->right, prefix + "1", codes);
}
