#include <queue>
#include <vector>
using namespace std;

HuffNode* buildHuffmanTree(const vector<char>& chars,
                           const vector<int>& freqs) {
    priority_queue<HuffNode*, vector<HuffNode*>, Compare> minHeap;

    for (size_t i = 0; i < chars.size(); ++i)
        minHeap.push(new HuffNode(chars[i], freqs[i]));

    while (minHeap.size() >= 2) {
        HuffNode* left  = minHeap.top(); minHeap.pop();
        HuffNode* right = minHeap.top(); minHeap.pop();
        int sum = left->freq + right->freq;
        minHeap.push(new HuffNode(sum, left, right));
    }

    return minHeap.top();
}
