#include <string>
#include <unordered_map>
using namespace std;

string encode(const string& message,
              const unordered_map<char, string>& codes) {
    string bits;
    for (char c : message)
        bits += codes.at(c);
    return bits;
}

string decode(const string& bits, HuffNode* root) {
    string result;
    HuffNode* node = root;
    for (char b : bits) {
        node = (b == '0') ? node->left : node->right;
        if (!node->left && !node->right) {
            result += node->ch;
            node = root;
        }
    }
    return result;
}
